        "group/cpu-info" = {
          orientation = "horizontal";
          modules = [
            "cpu"
            "temperature"
          ];
        };

        "hyprland/workspaces" = {
          format = "{id}";
          on-click = "activate";
          persistent-workspaces = {
            "*" = 5;
          };
        };

        clock = {
          format = "{:%H:%M}";
          format-alt = "{:%a, %b %d}";
          tooltip-format = "<tt><small>{calendar}</small></tt>";
          calendar = {
            mode = "year";
            mode-mon-col = 3;
            weeks-pos = "left";
            format = {
              months = "<span color='#f5e0dc'><b>{}</b></span>";
              days = "<span color='#cdd6f4'>{}</span>";
              weeks = "<span color='#94e2d5'><b>W{}</b></span>";
              weekdays = "<span color='#f9e2af'><b>{}</b></span>";
              today = "<span color='#cba6f7'><b><u>{}</u></b></span>";
            };
          };
        };

        "custom/weather" = {
          exec = "${waybar-weather}/bin/waybar-weather";
          return-type = "json";
          interval = 600;
        };

        mpris = {
          format = "{player_icon} {title} — {artist}";
          format-paused = "{status_icon} <i>{title} — {artist}</i>";
          title-len = 30;
          format-stopped = "󰝚";
          player-icons = {
            default = "󰝚";
          };
          status-icons = {
            paused = "󰏤";
          };
        };

        temperature = {
          format = "{temperatureC}°C";
          critical-threshold = 80;
          format-critical = "{temperatureC}°C";
          hwmon-path = "/sys/class/hwmon/hwmon2/temp1_input";
        };

        cpu = {
          format = "󰻠 {usage}%";
          interval = 2;
          on-click = "kitty btop";
        };

        "custom/gpu" = {
          exec = ''nvidia-smi --query-gpu=utilization.gpu,temperature.gpu --format=csv,noheader,nounits 2>/dev/null | awk -F', ' '{printf "{\"text\": \"󰢮 %s%% %s°C\", \"tooltip\": \"RTX 4090\\nUsage: %s%%\\nTemp: %s°C\"}", $1, $2, $1, $2}' '';
          return-type = "json";
          interval = 5;
          on-click = "kitty btop";
        };

        memory = {
          format = "󰍛 {percentage}%";
          format-alt = "󰍛 {used:0.1f}/{total:0.1f} GB";
          tooltip-format = "RAM: {used:0.1f}/{total:0.1f} GB\nSwap: {swapUsed:0.1f}/{swapTotal:0.1f} GB";
        };

        disk = {
          format = "󰋊 {percentage_used}%";
          format-alt = "󰋊 {used}/{total}";
          path = "/";
        };

        network = {
          format-wifi = " {signalStrength}%";
          format-ethernet = "󰈀 {ipaddr}";
          format-disconnected = "󰖪 ";
          tooltip-format = "{ifname}: {ipaddr}\n⬆ {bandwidthUpBits} ⬇ {bandwidthDownBits}";
        };

        pulseaudio = {
          format = "󰕾 {volume}%";
          format-muted = "󰖁 muted";
          format-bluetooth = "󰋋 {volume}%";
          format-bluetooth-muted = "󰖁 {device_alias}";
          tooltip-format = "{desc}\n{volume}%";
          scroll-step = 5;
          on-click = "kitty pulsemixer";
        };

        bluetooth = {
          format = "󰂯";
          format-connected = "󰂱 {device_alias}";
          format-connected-battery = "󰂱 {device_alias} {device_battery_percentage}%";
          format-disabled = "󰂲";
          format-off = "󰂲";
          tooltip-format-connected = "{device_enumerate}";
          tooltip-format-enumerate-connected-battery = "{device_alias}: {device_battery_percentage}%";
          on-click = "kitty bluetuith";
        };

        "custom/notification" = {
          exec = ''makoctl mode -l 2>/dev/null | grep -q do-not-disturb && echo '{"text": "󰂛", "tooltip": "Do not disturb", "class": "dnd"}' || echo '{"text": "󰂚", "tooltip": "Notifications", "class": "enabled"}' '';
          return-type = "json";
          interval = 5;
          on-click = "makoctl mode -t do-not-disturb";
          on-click-right = "makoctl dismiss -a";
          on-click-middle = "makoctl restore";
        };

        tray = {
          icon-size = 16;
          spacing = 8;
        };
      };
    };

    style = ''
      /* --- Catppuccin Mocha Palette --- */
      @define-color base #1e1e2e;
      @define-color mantle #181825;
      @define-color surface0 #313244;
