        min-height: 0;
      }

      window#waybar {
        background: transparent;
      }

      tooltip {
        background-color: alpha(@base, 0.9);
        border: 2px solid @surface0;
        border-radius: 12px;
        color: @text;
      }

      tooltip label {
        color: @text;
      }

      /* --- Pill Containers --- */
      #workspaces,
      #clock,
      #mpris,
      #pulseaudio,
      #memory,
      #disk,
      #network,
      #bluetooth,
      #custom-gpu,
      #custom-weather,
      #custom-notification,
      #tray {
        background-color: alpha(@base, 0.85);
        border: 2px solid @surface0;
        border-radius: 12px;
        padding: 0 12px;
        margin: 2px 3px;
        color: @text;
      }

