        color: @lavender;
      }

      #custom-weather {
        color: @sky;
      }

      #mpris {
        color: @mauve;
      }

      #temperature {
        color: @peach;
      }

      #temperature.critical {
        color: @red;
        animation: blink 0.5s ease infinite alternate;
      }

      #cpu {
        color: @sky;
      }

